class Solution:
    def sortString(self, s: str) -> str:
        s = list(s)
        res = []
        while s:
            smallest = min(s)
            res.append(smallest)
            s.remove(smallest)
            while s and s[0] > res[-1]:
                res.append(min([c for c in s if c > res[-1]]))
                s.remove(res[-1])
            if s:
                largest = max(s)
                res.append(largest)
                s.remove(largest)
                while s and s[0] < res[-1]:
                    res.append(max([c for c in s if c < res[-1]]))
                    s.remove(res[-1])
        return ''.join(res)

